member.example:
Bind the TMP_Dropdown value property using a serialized binder field — the target TMP_Dropdown is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private DropdownValueBinder _selectedIndex;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public int _selectedIndex;
    }


Bind the TMP_Dropdown value property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private TMP_Dropdown _dropdown;
        
        private DropdownValueBinder SelectedIndex =>
            new(_dropdown);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public int _selectedIndex;
    }

Switch the TMP_Dropdown value between two values using a serialized binder field — the target TMP_Dropdown is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private DropdownValueSwitcherBinder _isTabSelected;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isTabSelected;
    }


Switch the TMP_Dropdown value between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private TMP_Dropdown _dropdown;
        
        [SerializeField] 
        private int _selectedIndex;
        
        [SerializeField] 
        private int _defaultIndex;
        
        private DropdownValueSwitcherBinder IsTabSelected => new(
            _dropdown, _selectedIndex, _defaultIndex, null);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isTabSelected;
    }
